import json
user_question = "find restaurants and salons in san jose, California"
scout_result = await delegate_to_scout(task=user_question)
try:
    data = json.loads(scout_result.strip())
    candidates = data.get("candidates", []) or []
except (json.JSONDecodeError, ValueError, AttributeError):
    data, candidates = {}, []
top = candidates[:3]
enrichments = {}
for i in range(len(top)):
    enrichments[i] = {"candidate": top[i]}
status_msg = f"Got {len(candidates)} candidates; deep-diving top {len(top)}"
print(status_msg)
```

